await writeFile(lastMessagePath, 'runner final message\\n', 'utf8');
process.stdout.write(JSON.stringify({ type: 'turn.completed', usage: { total_tokens: 37 } }) + '\\n');
`, 'utf8');
  await chmod(fakeCodex, 0o755);
  return fakeCodex;
}

